 /// <summary>Provides web search and page-fetching tools using Wikipedia's public API.</summary>
 public sealed class WebSearcher(HttpClient httpClient)
 {
     [Description("Search the web for a query and return a list of relevant results with titles, snippets, and URLs.")]
     public async Task<string> SearchAsync(
         [Description("The search query")] string query,
         CancellationToken cancellationToken = default)
     {
         var encoded = Uri.EscapeDataString(query);
         var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={encoded}&srlimit=5&format=json";

         using var response = await httpClient.GetAsync(url, cancellationToken);
         response.EnsureSuccessStatusCode();

         using var doc = await JsonDocument.ParseAsync(
             await response.Content.ReadAsStreamAsync(cancellationToken), cancellationToken: cancellationToken);

         var results = doc.RootElement.GetProperty("query").GetProperty("search");
         if (results.GetArrayLength() == 0)
         {
             return "No results found.";
         }

         var sb = new StringBuilder();
         foreach (var item in results.EnumerateArray())
         {
             var title = item.GetProperty("title").GetString()!;
             var snippet = StripHtml(item.GetProperty("snippet").GetString() ?? "");
             var pageUrl = $"https://en.wikipedia.org/wiki/{Uri.EscapeDataString(title.Replace(' ', '_'))}";
             sb.AppendLine($"• {title}");
             sb.AppendLine($"  {snippet}");
             sb.AppendLine($"  URL: {pageUrl}");
             sb.AppendLine();
         }

         return sb.ToString();
     }

     [Description("Fetch a detailed summary of a Wikipedia page by its exact title.")]
     public async Task<string> FetchSummaryAsync(
         [Description("The exact Wikipedia page title")] string title,
         CancellationToken cancellationToken = default)
     {
         var encoded = Uri.EscapeDataString(title.Replace(' ', '_'));
         var url = $"https://en.wikipedia.org/api/rest_v1/page/summary/{encoded}";

         using var response = await httpClient.GetAsync(url, cancellationToken);
         if (response.StatusCode == HttpStatusCode.NotFound)
         {
             return $"Page not found: {title}";
         }

         response.EnsureSuccessStatusCode();

         using var doc = await JsonDocument.ParseAsync(
             await response.Content.ReadAsStreamAsync(cancellationToken), cancellationToken: cancellationToken);

         var root = doc.RootElement;
         var pageTitle = root.GetProperty("title").GetString();
         var extract = root.GetProperty("extract").GetString();
         var pageUrl = root.TryGetProperty("content_urls", out var urls)
             ? urls.GetProperty("desktop").GetProperty("page").GetString()
             : $"https://en.wikipedia.org/wiki/{encoded}";

         return $"""
             Title: {pageTitle}
             URL: {pageUrl}

             {extract}
             """;
     }

     private static string StripHtml(string html) =>
         System.Text.RegularExpressions.Regex.Replace(html, "<.*?>", "");
 }

 /// <summary>Provides in-memory note-taking tools for recording research findings.</summary>
 public sealed class NoteTaker
 {
     private readonly List<(string Title, string Content)> _notes = [];

     [Description("Save a research note with a title and content. Use this to record important findings.")]
     public string SaveNote(
         [Description("A short title for the note")] string title,
         [Description("The content or findings to save")] string content)
     {
         _notes.Add((title, content));
         return $"Note saved: \"{title}\" ({_notes.Count} total notes)";
     }

     [Description("Retrieve all saved research notes.")]
     public string GetNotes()
     {
         if (_notes.Count == 0)
         {
             return "No notes saved yet.";
         }

         var sb = new StringBuilder();
         for (int i = 0; i < _notes.Count; i++)
         {
             sb.AppendLine($"--- Note {i + 1}: {_notes[i].Title} ---");
             sb.AppendLine(_notes[i].Content);
             sb.AppendLine();
         }

         return sb.ToString();
     }
 }

